import os
import re
import socket
import ipaddress
import boto3
from urllib.parse import urlparse
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from flask import Flask, request, jsonify
import uuid
import time

app = Flask(__name__)

S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-service-bucket')
AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
ALLOWED_DOMAINS = set(os.environ.get('ALLOWED_DOMAINS', '').split(','))

s3_client = boto3.client('s3', region_name=AWS_REGION)


def is_private_ip(ip_str):
    try:
        ip = ipaddress.ip_address(ip_str)
        return (
            ip.is_private or
            ip.is_loopback or
            ip.is_link_local or
            ip.is_multicast or
            ip.is_reserved or
            str(ip).startswith('169.254.')
        )
    except ValueError:
        return True


def resolve_and_validate_host(hostname):
    try:
        ip_addresses = socket.getaddrinfo(hostname, None)
        for addr_info in ip_addresses:
            ip = addr_info[4][0]
            if is_private_ip(ip):
                return False, f"Resolved to private/internal IP: {ip}"
        return True, None
    except socket.gaierror:
        return False, "Unable to resolve hostname"


def validate_url(url):
    if not url or not isinstance(url, str):
        return False, "Invalid URL format"
    
    if not re.match(r'^https?://', url, re.IGNORECASE):
        return False, "Only HTTP and HTTPS protocols are allowed"
    
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Failed to parse URL"
    
    if not parsed.scheme or not parsed.netloc:
        return False, "Invalid URL structure"
    
    if parsed.scheme.lower() not in ['http', 'https']:
        return False, "Only HTTP and HTTPS protocols are allowed"
    
    hostname = parsed.hostname
    if not hostname:
        return False, "No hostname found in URL"
    
    hostname_lower = hostname.lower()
    
    if hostname_lower in ['localhost', '0.0.0.0']:
        return False, "Access to localhost is not allowed"
    
    try:
        ip = ipaddress.ip_address(hostname)
        if is_private_ip(str(ip)):
            return False, "Access to private IP addresses is not allowed"
    except ValueError:
        pass
    
    if ALLOWED_DOMAINS:
        domain_allowed = False
        for allowed_domain in ALLOWED_DOMAINS:
            if not allowed_domain:
                continue
            if hostname_lower == allowed_domain.lower() or hostname_lower.endswith('.' + allowed_domain.lower()):
                domain_allowed = True
                break
        
        if not domain_allowed:
            return False, f"Domain {hostname} is not in the allowlist"
    
    is_valid, error_msg = resolve_and_validate_host(hostname)
    if not is_valid:
        return False, error_msg
    
    return True, None


def create_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--window-size=1920,1080')
    chrome_options.add_argument('--disable-web-security')
    chrome_options.add_argument('--disable-features=IsolateOrigins,site-per-process')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36')
    
    chrome_options.set_capability('acceptInsecureCerts', False)
    
    prefs = {
        'profile.default_content_setting_values': {
            'notifications': 2,
            'geolocation': 2,
            'media_stream': 2
        }
    }
    chrome_options.add_experimental_option('prefs', prefs)
    
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_page_load_timeout(30)
    
    return driver


def capture_screenshot(url, output_path):
    driver = None
    try:
        driver = create_chrome_driver()
        
        driver.execute_cdp_cmd('Network.enable', {})
        driver.execute_cdp_cmd('Network.setBlockedURLs', {
            'urls': [
                '*://localhost/*',
                '*://127.0.0.1/*',
                '*://169.254.169.254/*',
                '*://10.*',
                '*://172.16.*',
                '*://172.17.*',
                '*://172.18.*',
                '*://172.19.*',
                '*://172.20.*',
                '*://172.21.*',
                '*://172.22.*',
                '*://172.23.*',
                '*://172.24.*',
                '*://172.25.*',
                '*://172.26.*',
                '*://172.27.*',
                '*://172.28.*',
                '*://172.29.*',
                '*://172.30.*',
                '*://172.31.*',
                '*://192.168.*'
            ]
        })
        
        driver.get(url)
        time.sleep(2)
        
        final_url = driver.current_url
        is_valid, error_msg = validate_url(final_url)
        if not is_valid:
            raise Exception(f"Redirect validation failed: {error_msg}")
        
        driver.save_screenshot(output_path)
        return True, None
    except Exception as e:
        return False, str(e)
    finally:
        if driver:
            driver.quit()


def upload_to_s3(file_path, s3_key):
    try:
        s3_client.upload_file(
            file_path,
            S3_BUCKET,
            s3_key,
            ExtraArgs={'ContentType': 'image/png', 'ACL': 'private'}
        )
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{s3_key}"
        return True, url
    except Exception as e:
        return False, str(e)


@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.get_json()
    
    if not data or 'url' not in data:
        return jsonify({'error': 'URL is required'}), 400
    
    url = data['url']
    
    is_valid, error_msg = validate_url(url)
    if not is_valid:
        return jsonify({'error': f'Invalid URL: {error_msg}'}), 400
    
    screenshot_id = str(uuid.uuid4())
    temp_file = f'/tmp/screenshot_{screenshot_id}.png'
    s3_key = f'screenshots/{screenshot_id}.png'
    
    try:
        success, error = capture_screenshot(url, temp_file)
        if not success:
            return jsonify({'error': f'Screenshot failed: {error}'}), 500
        
        success, result = upload_to_s3(temp_file, s3_key)
        if not success:
            return jsonify({'error': f'Upload failed: {result}'}), 500
        
        return jsonify({
            'success': True,
            'screenshot_id': screenshot_id,
            's3_key': s3_key,
            'url': result
        }), 200
    
    finally:
        if os.path.exists(temp_file):
            os.remove(temp_file)


@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)